{"path":"/Users/brian/src/tim/tim/logviewer.py","content":"import json
import re
from html import escape
from pathlib import Path
from typing import NamedTuple


class LogEntry(NamedTuple):
    agent: str
    agent_instance: int
    timestamp: str
    role: str
    content: str
    reasoning: str | None
    tool_call_id: str | None
    tool_call_name: str | None
    tool_arguments: str | None
    prompt_tokens: int | None
    completion_tokens: int | None


ANSI_RE = re.compile(r'\x1b\[[0-9;]*m')


def _strip_ansi(text: str) -> str:
    return ANSI_RE.sub('', text)


def _format_timestamp(iso_string: str) -> str:
    date_part, _sep, rest = iso_string.partition('T')
    time_part = rest.rsplit('+', 1)[0].rsplit('-', 1)[0]
    return f"{date_part} {time_part}"


def _extract_tool_info(message: dict) -> dict:
    tool_calls = message.get("tool_calls")
    if tool_calls:
        first = tool_calls[0]
        return {
            "id": first.get("id"),
            "name": first.get("name"),
            "arguments": first.get("arguments"),
        }
    return {"id": None, "name": None, "arguments": None}


def _parse_log_file(log_file_path: Path) -> list[LogEntry]:
    entries: list[LogEntry] = []
    with open(log_file_path, encoding='utf-8') as fh:
        for raw_line in fh:
            line = raw_line.strip()
            if not line:
                continue
            record = json.loads(line)
            message = record["message"]
            usage = record.get("usage", {})
            tool = _extract_tool_info(message)
            entries.append(LogEntry(
                agent=record["source"]["agent"],
                agent_instance=record["source"]["agent_instance"],
                timestamp=record["at"],
                role=message["role"],
                content=_strip_ansi(message.get("content") or ""),
                reasoning=message.get("reasoning"),
                tool_call_id=tool["id"],
                tool_call_name=tool["name"],
                tool_arguments=tool["arguments"],
                prompt_tokens=usage.get("prompt_tokens"),
                completion_tokens=usage.get("completion_tokens"),
            ))
    return entries


def _esc(text: str) -> str:
    return escape(text) if text else ""


def _format_arguments(json_string: str) -> str:
    try:
        return _esc(json.dumps(json.loads(json_string), indent=2))
    except (json.JSONDecodeError, TypeError):
        return _esc(json_string)


def _agent_display_name(agent: str) -> str:
    return agent


def _entry_meta(entry: LogEntry) -> str:
    ts = _format_timestamp(entry.timestamp)
    label = f"{_agent_display_name(entry.agent)} ({entry.agent_instance})"
    return (
        f"<div class='log-meta'>"
        f"<span class='timestamp'>{ts}</span>"
        f"<span class='agent-label'>{label}</span>"
        f"</div>"
    )


def _body_system(entry: LogEntry) -> str:
    content = _esc(entry.content)
    return (
        f'<details class="message-system">'
        f'<summary>System</summary>'
        f'<div class="message-content"><pre>{content}</pre></div>'
        f'</details>'
    )


def _body_user(entry: LogEntry) -> str:
    content = _esc(entry.content)
    return (
        f'<div class="message user">'
        f'<div class="message-content"><pre>{content}</pre></div>'
        f'</div>'
    )


def _body_assistant(entry: LogEntry) -> str:
    parts: list[str] = []
    if entry.reasoning:
        parts.append(
            f'<details class="reasoning">'
            f'<summary>Reasoning</summary>'
            f'<pre>{_esc(entry.reasoning)}</pre>'
            f'</details>'
        )
    if entry.tool_call_name:
        cid = _esc(entry.tool_call_id) if entry.tool_call_id else ""
        args = _format_arguments(entry.tool_arguments) if entry.tool_arguments else ""
        parts.append(
            f'<details class="tool-call">'
            f'<summary>{_esc(entry.tool_call_name)} <code>{cid}</code></summary>'
            f'<pre>{args}</pre>'
            f'</details>'
        )
    if parts:
        return f'<div class="message assistant">{"".join(parts)}</div>'
    content = _esc(entry.content)
    return (
        f'<div class="message assistant">'
        f'<div class="message-content"><pre>{content}</pre></div>'
        f'</div>'
    )


def _body_tool(entry: LogEntry) -> str:
    cid = _esc(entry.tool_call_id) if entry.tool_call_id else "unknown"
    result = _esc(entry.content) if entry.content else "<em>No output</em>"
    return (
        f'<details class="tool-output">'
        f'<summary>Tool response <code>{cid}</code></summary>'
        f'<pre>{result}</pre>'
        f'</details>'
    )


def _entry_body(entry: LogEntry) -> str:
    role = entry.role
    if role == "system":
        return _body_system(entry)
    if role == "user":
        return _body_user(entry)
    if role == "assistant":
        return _body_assistant(entry)
    if role == "tool":
        return _body_tool(entry)
    content = _esc(entry.content)
    return (
        f'<div class="message">'
        f'<div class="message-content"><pre>{content}</pre></div>'
        f'</div>'
    )


def _entry_html(entry: LogEntry) -> str:
    meta = _entry_meta(entry)
    body = _entry_body(entry)
    return f"<div class=\"log-entry\">{meta}<div class='log-body'>{body}</div></div>"


def _header_title(agent: str) -> str:
    return f"Agent Log - {_agent_display_name(agent)}"


def _header_subtitle(entries: list[LogEntry], log_path: Path) -> str:
    name = _esc(log_path.name)
    count = len(entries)
    if entries:
        start = _format_timestamp(entries[0].timestamp)
        end = _format_timestamp(entries[-1].timestamp)
        time_range = f"{start} - {end}"
    else:
        time_range = ""
    return f"{name} | {count} entries | {time_range}"


def _render_html(entries: list[LogEntry], log_file_path: Path) -> str:
    title = _header_title(entries[0].agent) if entries else "Agent Log"
    subtitle = _header_subtitle(entries, log_file_path)
    entries_html = "\n".join(_entry_html(e) for e in entries)
    style = _style_css()
    return (
        f"<!DOCTYPE html>\n"
        f"<html lang='en'>\n"
        f"<head>\n"
        f"<meta charset='utf-8'>\n"
        f"<meta name='viewport' content='width=device-width, initial-scale=1'>\n"
        f"<title>{title}</title>\n"
        f"<style>{style}</style>\n"
        f"</head><body>\n"
        f'<div class="header"><h1>{title}</h1><p>{subtitle}</p></div>\n'
        f"{entries_html}\n"
        f"</body>\n"
        f"</html>\n"
    )


def _style_css() -> str:
    return (
        "body { font-family: -apple-system, BlinkMacSystemFont, 'Segoe UI', Roboto, sans-serif; "
        "max-width: 960px; margin: 0 auto; padding: 2rem; background: #f5f5f5; color: #333; } "
        ".header { background: #2c3e50; color: white; padding: 1.5rem; border-radius: 8px; margin-bottom: 1.5rem; } "
        ".header h1 { margin: 0 0 0.5rem 0; font-size: 1.5rem; } "
        ".header p { margin: 0; opacity: 0.8; font-size: 0.9rem; } "
        ".log-entry { background: white; border: 1px solid #ddd; border-radius: 6px; margin-bottom: 0.75rem; overflow: hidden; } "
        ".log-meta { background: #f8f9fa; padding: 0.5rem 1rem; border-bottom: 1px solid #eee; display: flex; gap: 1rem; font-size: 0.85rem; } "
        ".timestamp { color: #666; } "
        ".agent-label { color: #2c3e50; font-weight: 500; } "
        ".log-body { padding: 1rem; } "
        ".message { padding: 0.5rem 0; } "
        ".message-content { margin-top: 0.5rem; } "
        "pre { background: #f8f9fa; padding: 0.75rem; border-radius: 4px; overflow-x: auto; font-size: 0.9rem; white-space: pre-wrap; word-wrap: break-word; } "
        ".message-system > summary { cursor: pointer; padding: 0.5rem; background: #e3f2fd; border-radius: 4px; } "
        ".reasoning > summary { cursor: pointer; color: #666; font-style: italic; padding: 0.5rem 0; } "
        ".tool-call > summary { cursor: pointer; color: #1976d2; font-weight: 500; padding: 0.5rem 0; } "
        ".tool-output > summary { cursor: pointer; color: #388e3c; font-weight: 500; padding: 0.5rem 0; } "
        "code { background: #e9ecef; padding: 0.15rem 0.35rem; border-radius: 3px; font-size: 0.85em; }"
    )


def read_log_file(log_file_path: Path) -> list[LogEntry]:
    if not log_file_path.is_file():
        raise FileNotFoundError(f"Log file not found: {log_file_path}")
    return _parse_log_file(log_file_path)


def generate_html(entries: list[LogEntry], log_file_path: Path) -> str:
    return _render_html(entries, log_file_path)
"}

